          lastRotated: "2026-03-01",
          rotationDays: 180,
          requiredBy: ["app"],
        },
      ],
    },
    warningDays: 14,
    referenceDate: "2026-04-17",
    expect: {
      actExit: 0,
      expired: 0,
      warning: 0,
      ok: 2,
      okNames: ["analytics-token", "feature-flag-key"],
    },
  },
