          name: "stripe-webhook",
          lastRotated: "2026-01-20",
          rotationDays: 90,
          requiredBy: ["billing"],
        },
        {
          name: "analytics-token",
          lastRotated: "2026-04-10",
          rotationDays: 365,
          requiredBy: ["dashboards"],
        },
      ],
    },
    warningDays: 14,
    referenceDate: "2026-04-17",
    expect: {
      actExit: 0,
      expired: 0,
      warning: 1,
      ok: 1,
      warningNames: ["stripe-webhook"],
      okNames: ["analytics-token"],
    },
