    id: "one-expired",
    description: "One secret overdue ⇒ workflow fails with exit 1.",
    fixture: {
      secrets: [
        {
          name: "prod-db-password",
          lastRotated: "2025-10-01",
          rotationDays: 60,
          requiredBy: ["api", "worker"],
        },
        {
          name: "feature-flag-key",
          lastRotated: "2026-04-10",
          rotationDays: 180,
          requiredBy: ["app"],
        },
      ],
    },
    warningDays: 14,
    referenceDate: "2026-04-17",
    expect: {
      actExit: 1,
      expired: 1,
      warning: 0,
      ok: 1,
